diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..a4a522d91100 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,36 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq/ne (and (add A, Addend), ~(-Addend << 1)), 0)
+  //    -> (icmp ne/eq (and A, -Addend), 0)
+  // if -Addend is a power of 2 (i.e., Addend is a negated power of 2).
+  // This handles patterns like:
+  // ((x - 1) & -3) == 0 -> (x & 1) != 0  (checking low bit is set)
+  {
+    Value *A;
+    const APInt *Addend, *Mask;
+    if (C.isZero() &&
+        match(And, m_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                         m_APInt(Mask)))) {
+      // Check if Addend is a negated power of 2 (e.g., -1, -2, -4, ...)
+      APInt NegAddend = -(*Addend);
+      if (NegAddend.isPowerOf2()) {
+        // The mask should be ~(NegAddend << 1), i.e., all bits except
+        // the bit just above NegAddend
+        APInt ExpectedMask = ~(NegAddend << 1);
+        if (*Mask == ExpectedMask) {
+          // Transform: ((A + Addend) & Mask) == 0  ->  (A & NegAddend) != 0
+          // The predicate is flipped because the original returns true when
+          // A is exactly NegAddend or 0 (modulo higher bits cleared by mask)
+          auto NewPred = Pred == CmpInst::ICMP_EQ ? CmpInst::ICMP_NE
+                                                  : CmpInst::ICMP_EQ;
+          Value *NewAnd = Builder.CreateAnd(A, ConstantInt::get(A->getType(), NegAddend));
+          return new ICmpInst(NewPred, NewAnd, Constant::getNullValue(A->getType()));
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

@@ -2026,8 +2056,6 @@ static Value *foldICmpOrXorSubChain(ICmpInst &Cmp, BinaryOperator *Or,
   // Are we using xors or subs to bitwise check for a pair or pairs of
   // (in)equalities? Convert to a shorter form that has more potential to be
   // folded even further.
-  // ((X1 ^/- X2) || (X3 ^/- X4)) == 0 --> (X1 == X2) && (X3 == X4)
-  // ((X1 ^/- X2) || (X3 ^/- X4)) != 0 --> (X1 != X2) || (X3 != X4)
   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) == 0 -->
   // (X1 == X2) && (X3 == X4) && (X5 == X6)
   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) != 0 -->
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 147d2060e850..861aae425416 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -680,6 +680,40 @@ private:
         }
       }

+      // (icmp eq/ne (and (add X, Addend), Mask), 0)
+      //    -> (icmp ne/eq (and X, -Addend), 0)
+      // if -Addend is a power of 2.
+      // This pattern handles cases like:
+      // ((x - 1) & -3) == 0 -> (x & 1) != 0
+      // ((x - 2) & -5) == 0 -> (x & 2) != 0  
+      // i.e., checking if x is exactly one of 0 or -Addend
+      {
+        Value *X;
+        const APInt *Addend, *Mask;
+        if (C->isZero() &&
+            match(ICI->getOperand(0),
+                  m_And(m_Add(m_Value(X), m_APInt(Addend)),
+                        m_APInt(Mask)))) {
+          APInt NegAddend = -(*Addend);
+          // Check if NegAddend is a power of 2
+          if (NegAddend.isPowerOf2()) {
+            // The mask should be ~(NegAddend << 1)
+            APInt ExpectedMask = ~(NegAddend << 1);
+            if (*Mask == ExpectedMask) {
+              // The values that satisfy the eq check are X == 0 OR X == NegAddend
+              // This is equivalent to: the result (X + Addend) has no bits 1 and above
+              if (!setValueOnce(X))
+                return false;
+              Vals.push_back(ConstantInt::get(C->getContext(),
+                                              APInt(Addend->getBitWidth(), 0)));
+              Vals.push_back(ConstantInt::get(C->getContext(), NegAddend));
+              UsedICmps++;
+              return true;
+            }
+          }
+        }
+      }
+
       // If we already have a value for the switch, it has to match!
       if (!setValueOnce(ICI->getOperand(0)))
         return false;

