  2057 |   // (in)equalities? Convert to a shorter form that has more potential to be
  2058 |   // folded even further.
  2059 |   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) == 0 -->
  2060 |   // (X1 == X2) && (X3 == X4) && (X5 == X6)
