  2062 |   // (X1 != X2) || (X3 != X4) || (X5 != X6)
  2063 |   SmallVector<std::pair<Value *, Value *>, 2> CmpValues;
  2064 |   SmallVector<Value *, 16> WorkList(1, Or);
  2065 | 
  2066 |   while (!WorkList.empty()) {
